import { onAuthStateChanged } from "firebase/auth";
import React, { createContext, useContext, useEffect, useState } from "react";

// Import Firebase auth directly from the project's central firebase.js
import { auth as typedAuth } from "../../firebase.js";

import { signOutUser } from "./auth.js";
import { getUserDoc, setUserDoc } from "./firestoreClient.js";
import { normalizeRole } from "./normalizeRole.js";

// Small Role type to document expected values in the app.
export type Role = "educator" | "learner" | string;

type User = {
  id: string;
  role?: Role;
};

/* eslint-disable @typescript-eslint/no-unused-vars */
// type-only shape for the React context
// eslint-disable-next-line @typescript-eslint/no-unused-vars
type UserContextType = {
  user: User | null;
  setUser: React.Dispatch<React.SetStateAction<User | null>>;
  logout: () => void;
};
/* eslint-enable @typescript-eslint/no-unused-vars */

const UserContext = createContext<UserContextType>({
  user: null,
  setUser: () => {},
  logout: () => {},
});

export function useUser() {
  return useContext(UserContext);
}

export function UserProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const fbAuth = typedAuth;
    if (!fbAuth) return;

    const unsub = onAuthStateChanged(fbAuth, async (firebaseUser) => {
      if (!firebaseUser) {
        setUser(null);
        return;
      }
      const uid = firebaseUser.uid;
      // attempt to read role from Firestore users/{uid} using centralized client
      try {
        const data = await getUserDoc(uid);
        // normalize legacy role strings if present (trainer->educator, student->learner)
        // (uses top-level `normalizeRole` helper)

        if (!data) {
          // create a minimal user doc with default role 'learner'
          try {
            await setUserDoc(uid, {
              role: "learner",
              name: firebaseUser.displayName || "",
              email: firebaseUser.email || "",
            });
          } catch (writeErr) {
            // Firestore write failed (permissions) - continue with local role
            console.warn("Could not save user profile to Firestore, using local state");
          }
          setUser({ id: uid, role: "learner" });
        } else {
          const role = normalizeRole(data.role) || "learner";
          setUser({ id: uid, role });
        }
      } catch (e) {
        // Firestore read failed - use local user state without persisted role
        // This commonly happens when Firestore rules aren't deployed or offline
        console.warn("Could not fetch user role from Firestore, using default role");
        setUser({ id: uid, role: "learner" });
      }
    });

    return () => unsub();
  }, []);

  const logout = () => {
    // Use centralized signOut helper which logs failures safely
    signOutUser().catch(() => {});
    setUser(null);
  };

  return <UserContext.Provider value={{ user, setUser, logout }}>{children}</UserContext.Provider>;
}
